s($,"bcw","aVL",()=>{var q,p,o,n,m,l,k,j=null,i=t.s,h=A.b(["Stay calm \u2014 panic speeds up venom spread. Reassure the victim.","Keep the bitten limb still and below heart level.","Remove rings, watches, or tight clothing near the bite.","Mark the edge of swelling with a pen and note the time.","Do NOT apply a tourniquet, cut the wound, or suck venom.","Do NOT apply ice or herbal remedies to the bite.","Transport the victim to the nearest emergency hospital IMMEDIATELY.","Note the snake's appearance (colour, markings) if safe to do so \u2014 do not try to catch it."],i),g=A.b(["\u26a0\ufe0f This is a CRITICAL emergency \u2014 go to hospital even if no symptoms yet.","\u26a0\ufe0f Anti-venom must be given by a doctor; do NOT attempt home treatment.",'\u26a0\ufe0f Symptoms may be delayed 30\u201360 minutes. Never wait to "see if it gets bad".'],i)
g=A.qo("Snake Bite",j,j,"snake venom bite poison rural reptile fangs",A.b(["Critical","emergency","poison"],i),h,g)
h=A.b(["Remove the victim from the source of heat immediately.","Remove any clothing or jewellery near the burnt area (unless stuck to skin).","Cool the burn under cool (not cold) running water for 10\u201320 minutes.","Do NOT use ice, butter, toothpaste, or any oils on the burn.","Cover loosely with a clean, non-fluffy material (e.g., cling film or a clean cloth).","For small burns (smaller than the victim's palm), keep cool and covered.","For large burns (face, hands, genitals, or >1% body area): go to hospital immediately.","Give paracetamol or ibuprofen for pain if available and victim is conscious."],i)
q=A.b(["\u26a0\ufe0f Chemical burns: flush with water for at least 20 minutes. Remove contaminated clothing carefully.","\u26a0\ufe0f Electrical burns: do NOT touch victim if still in contact with power source.","\u26a0\ufe0f Seek emergency help for burns involving face, airway, hands, or large body surface."],i)
q=A.qo("Burns",j,j,"burn fire scald hot water flame blister skin thermal",A.b(["High","thermal","chemical"],i),h,q)
h=A.b(["Apply firm pressure with a clean cloth or bandage for at least 10 minutes.","Do NOT remove the cloth if soaked \u2014 add more on top.","Once bleeding stops, clean the wound gently with clean water.","Apply antiseptic (Dettol, Savlon, or Betadine) and cover with a sterile bandage.","For deep wounds: do NOT remove embedded objects; stabilise and go to hospital.","Check tetanus vaccination status \u2014 update if the wound is dirty or deep."],i)
p=A.b(["\u26a0\ufe0f Go to hospital for: spurting blood, wounds that won't stop bleeding in 15 min, deep cuts, bites.","\u26a0\ufe0f Do NOT use tourniquet except for life-threatening limb bleeding.","\u26a0\ufe0f Signs of infection (redness, warmth, pus, fever) require medical attention."],i)
p=A.qo("Cuts & Wounds",j,j,"cut wound laceration bleeding scratch graze knife glass",A.b(["Low","wound","laceration"],i),h,p)
h=A.b(["Keep the injured person still. Do NOT try to straighten the limb.","Immobilise the fracture using a splint or by padding and bandaging it in the position found.","If a splint is unavailable, use a rigid object (stick, folded newspaper) padded with cloth.","Apply ice wrapped in cloth to reduce swelling (20 min on, 20 min off).","Elevate the injured limb if possible without moving it further.","For suspected spine fractures: do NOT move the victim at all without emergency support.","Transport to hospital for X-ray and proper treatment."],i)
o=A.b(["\u26a0\ufe0f Open fractures (bone through skin): cover with clean cloth \u2014 do NOT push bone back.","\u26a0\ufe0f Suspected neck or spine injury: do NOT move the person. Call emergency services.","\u26a0\ufe0f Seek emergency care if circulation/sensation is lost below the injury."],i)
o=A.qo("Fracture (Broken Bone)",j,j,"fracture broken bone crack spine neck arm leg fall trauma",A.b(["High","orthopaedic","trauma"],i),h,o)
h=A.b(["Move the person to a cool, shaded area immediately.","Call emergency services / arrange transport to hospital NOW.","Remove excess clothing.","Cool the body rapidly: apply cool wet cloths to skin, especially neck, armpits, groin.","Fan the person while applying cool water.","If conscious and able to swallow, give cool water to sip.","Do NOT give alcohol or caffeine.","Place unconscious victims in the recovery position."],i)
n=A.b(["\u26a0\ufe0f Heat stroke is LIFE-THREATENING \u2014 body temperature above 40\xb0C can cause organ damage.","\u26a0\ufe0f Confusion, seizures, or loss of consciousness: this is Critical \u2014 call emergency immediately.","\u26a0\ufe0f Do NOT give fever medication (paracetamol) \u2014 it will not help in heat stroke."],i)
n=A.qo("Heat Stroke",j,j,"heat stroke sun exhaustion temperature summer hot unconscious",A.b(["Critical","heat","hyperthermia"],i),h,n)
h=A.b(["Catch the person gently if you can to prevent injury from falling.","Lay the person flat on their back on a firm surface.","Raise their legs 15\u201330 cm above heart level (if no suspected injury).","Loosen any tight clothing around the neck and waist.","Ensure fresh air \u2014 open windows or ask bystanders to step back.","Check breathing \u2014 if not breathing, begin CPR.","If breathing normally, they should regain consciousness within 1\u20132 minutes.","Once conscious, keep them lying down for a few minutes before sitting up."],i)
m=A.b(["\u26a0\ufe0f Seek medical attention if person does not regain consciousness within 2 minutes.","\u26a0\ufe0f Call emergency if fainted after chest pain, head injury, or difficulty breathing.","\u26a0\ufe0f Do NOT give liquids until fully conscious and able to swallow safely."],i)
m=A.qo("Fainting (Unconsciousness)",j,j,"faint unconscious dizzy collapse syncope blackout pass out",A.b(["Moderate","syncope","collapse"],i),h,m)
h=A.b(["Protect yourself with gloves or extra layers of cloth if available.","Apply firm, direct pressure to the wound with a clean cloth or bandage.","Hold pressure continuously for at least 10\u201315 minutes without lifting to check.","If blood soaks through, add more material on top \u2014 do NOT remove first layer.","Elevate the bleeding body part above heart level if possible.","For limb bleeding that cannot be controlled: apply tourniquet 5\u20137 cm above wound.","Note tourniquet time and transport to hospital IMMEDIATELY."],i)
l=A.b(["\u26a0\ufe0f Bright red spurting blood = arterial bleed = CRITICAL. Apply maximum pressure and call emergency.","\u26a0\ufe0f Do NOT remove objects embedded in wounds \u2014 stabilise and take to hospital.","\u26a0\ufe0f A tourniquet should only be used for life-threatening limb bleeding."],i)
l=A.qo("Severe Bleeding",j,j,"bleeding blood wound gash haemorrhage tourniquet artery vein",A.b(["High","haemorrhage","blood"],i),h,l)
h=A.b(['Ask the person: "Are you choking?" \u2014 if they cannot speak/cough/breathe, act immediately.',"Encourage the person to cough hard if they can.","Stand behind them, lean them forward slightly.","Give up to 5 firm back blows between shoulder blades with heel of your hand.","Check mouth \u2014 remove any visible obstruction.","If still choking: give up to 5 abdominal thrusts (Heimlich manoeuvre).","Alternate 5 back blows and 5 abdominal thrusts until object is dislodged.","If the person becomes unconscious: begin CPR and call emergency services.","For infants: use 5 back blows + 5 chest thrusts (NOT abdominal thrusts)."],i)
k=A.b(["\u26a0\ufe0f Choking is LIFE-THREATENING \u2014 act within seconds.","\u26a0\ufe0f Do NOT perform abdominal thrusts on infants under 1 year.","\u26a0\ufe0f Seek medical attention after any choking episode \u2014 internal injury is possible."],i)
return A.b([g,q,p,o,n,m,l,A.qo("Choking",j,j,"choking airway obstruction Heimlich throat food object suffocate",A.b(["Critical","airway","obstruction"],i),h,k)],t.yw)})
